+		Version: 1,
+		Env:     map[string]string{"GT_DOLT_PORT": "3307"},
+		Patrols: &PatrolsConfig{
+			WispReaper: &WispReaperConfig{
+				Enabled:     true,
+				IntervalStr: "1h",
+			},
+		},
+	}
